import React, { useContext, useState } from "react";
import { Alert, Button, Snackbar, TextField } from "@mui/material";
import { AdminAuthContext } from "../contexts/AdminAuthContext";
import "../App.css";

function AdminLogin() {
  const [usernameOrEmail, setUsernameOrEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const { loginAdmin } = useContext(AdminAuthContext);

  const onSubmit = async (event) => {
    event.preventDefault();
    const value = usernameOrEmail.trim();
    if (!value || !password.trim()) {
      setError("Username/Email and password are required.");
      return;
    }

    try {
      await loginAdmin({
        username: value.includes("@") ? "" : value,
        email: value.includes("@") ? value : "",
        password: password.trim(),
      });
    } catch (e) {
      setError(e?.response?.data?.message || "Unable to login");
    }
  };

  return (
    <div className="adminLoginPage">
      <div className="adminLoginCard">
        <p className="adminOverline">Zomeetix</p>
        <h1>Admin Console</h1>
        <p className="adminSubtext">Sign in to manage meetings, schedules and recordings.</p>

        <form onSubmit={onSubmit} className="adminLoginForm">
          <TextField
            label="Username or Email"
            value={usernameOrEmail}
            onChange={(e) => setUsernameOrEmail(e.target.value)}
            fullWidth
            size="small"
          />
          <TextField
            label="Password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            fullWidth
            size="small"
          />
          <Button type="submit" variant="contained">
            Login to Admin
          </Button>
        </form>
      </div>

      <Snackbar
        open={Boolean(error)}
        autoHideDuration={3000}
        onClose={() => setError("")}
      >
        <Alert severity="error" onClose={() => setError("")}>
          {error}
        </Alert>
      </Snackbar>
    </div>
  );
}

export default AdminLogin;
